const item = $input.first();
let emailCliente = 'SIN_EMAIL';

const fromField = item.json.from;

if (fromField && typeof fromField === 'object' && fromField.value && fromField.value[0]) {
  emailCliente = fromField.value[0].address;
} else if (typeof fromField === 'string') {
  const match = fromField.match(/<(.+)>/);
  emailCliente = match ? match[1] : fromField.replace('From: ', '').trim();
}

item.json.emailCliente = emailCliente;
return [item];

// ===== 1. Normalizar los datos de entrada =====
function parseImporte(valor) {
  if (typeof valor === 'number') return valor;
  if (!valor) return 0;
  let str = String(valor).trim();
  str = str.replace(/[$\s]/g, '');
  if (str.includes(',') && str.includes('.')) {
    str = str.replace(/\./g, '').replace(',', '.');
  } else if (str.includes(',')) {
    str = str.replace(',', '.');
  }
  const num = parseFloat(str);
  return isNaN(num) ? 0 : num;
}

const filas = $input.all().map(item => {
  const j = item.json;
  const keys = Object.keys(j);
  const codigoKey = keys.find(k => /cod/i.test(k));
  const descKey = keys.find(k => /desc|detalle|concepto/i.test(k));
  const importeKey = keys.find(k => /import|monto|precio|total/i.test(k));

  return {
    codigo: parseInt(String(j[codigoKey]).trim(), 10),
    descripcion: j[descKey] ? String(j[descKey]).trim() : '',
    importe: parseImporte(j[importeKey])
  };
}).filter(f => !isNaN(f.codigo));

// ===== 2. Función helper: sumar por rango, con exclusiones opcionales =====
function sumarRango(desde, hasta, excluir = []) {
  return filas
    .filter(f => f.codigo >= desde && f.codigo <= hasta && !excluir.includes(f.codigo))
    .reduce((acc, f) => acc + f.importe, 0);
}

function detalleRango(desde, hasta) {
  return filas
    .filter(f => f.codigo >= desde && f.codigo <= hasta)
    .map(f => ({ codigo: f.codigo, descripcion: f.descripcion, importe: f.importe }));
}

// ===== 3. Ventas (código 511000) =====
const ventas = filas.find(f => f.codigo === 511000)?.importe || 0;

// ===== 4. Costo de Producción (A + B + C) =====
const itemA = sumarRango(641009, 641011);
const itemB = sumarRango(651001, 659004, [654001, 654002, 654003]);

const detalleC = [
  ...detalleRango(641001, 641008),
  ...detalleRango(654001, 654003)
];
const itemC = detalleC.reduce((acc, f) => acc + f.importe, 0);

const costoProduccion = itemA + itemB + itemC;

// ===== 5. Gastos operativos (D, E, F) =====
const itemD = sumarRango(611001, 618521);
const itemE = sumarRango(621001, 624001);
const itemF = sumarRango(631001, 634002);

// ===== 6. Estado de Resultados =====
const rechazo = ventas * 0.01;
const ventasNetas = ventas - rechazo;
const resultadoBruto = ventasNetas - costoProduccion;
const resultadoNeto = resultadoBruto - itemD - itemE - itemF;

// ===== 7. Salida =====
return [{
  json: {
           costoDeProduccion: {
      itemA_manoDeObra: itemA,
      itemB_gastosFabricacion: itemB,
      itemC_costoDirectoFabricacion: itemC,
      detalleC: detalleC,
      total: costoProduccion
    },
    estadoDeResultados: {
      ventas: ventas,
      rechazo: rechazo,
      ventasNetas: ventasNetas,
      costoDeProduccion: costoProduccion,
      resultadoBruto: resultadoBruto,
      gastosAdministracion: itemD,
      gastosComercializacion: itemE,
      gastosFinanciacion: itemF,
      resultadoNeto: resultadoNeto
    }
  }
}];
